/**
 * Exercises theme loading with a constrained heap so estimator eviction, persistence, unload, reload, and query
 * planning all run in the same benchmark operation.
 */
@State(Scope.Thread)
@BenchmarkMode(Mode.SingleShotTime)
@OutputTimeUnit(TimeUnit.SECONDS)
@Warmup(iterations = 0)
@Measurement(iterations = 1)
@Fork(value = 1, jvmArgs = { "-Xms512m", "-Xmx512m", "-XX:+UseG1GC" })
public class SketchEstimatorThemeMemoryBenchmark {

	private static final String BENCHMARK_DIRECTORY = "target/lmdb-sketch-theme-memory-benchmark";
	private static final String ESTIMATOR_PROPERTY_PREFIX = "org.eclipse.rdf4j.sail.base.SketchBasedJoinEstimator.";
	private static final String LIBRARY = "http://example.com/theme/library/";
	private static final String MEDICAL = "http://example.com/theme/medical/";
	private static final int STANDARD_BUCKET_COUNT = 1024;
	private static final int STANDARD_SKETCH_NOMINAL_ENTRIES = 4096;
	private static final int HIGH_BUCKET_COUNT = 4096;
	private static final int HIGH_SKETCH_NOMINAL_ENTRIES = 8192;
	private static final EstimatorPrecision STANDARD_PRECISION = new EstimatorPrecision(STANDARD_BUCKET_COUNT,
			STANDARD_SKETCH_NOMINAL_ENTRIES);
	private static final EstimatorPrecision HIGH_PRECISION = new EstimatorPrecision(HIGH_BUCKET_COUNT,
			HIGH_SKETCH_NOMINAL_ENTRIES);

	@Param({ "ALL" })
	public String themeSet;

	@Benchmark
	public long incrementalPersistentAllThemes512m() throws Exception {
		return runThemeLoadBenchmark("incremental-standard", STANDARD_PRECISION, LoadMode.INCREMENTAL);
	}

	@Benchmark
	public long bulkRebuildPersistentAllThemes512m() throws Exception {
		return runThemeLoadBenchmark("bulk-rebuild-standard", STANDARD_PRECISION, LoadMode.BULK_REBUILD);
	}

	@Benchmark
	public long highPrecisionIncrementalAllThemes512m() throws Exception {
		return runThemeLoadBenchmark("incremental-high-precision", HIGH_PRECISION, LoadMode.INCREMENTAL);
	}

	private long runThemeLoadBenchmark(String name, EstimatorPrecision precision, LoadMode mode) throws Exception {
		List<Theme> themes = selectedThemes();
		Path benchmarkRoot = Path.of(BENCHMARK_DIRECTORY);
		Files.createDirectories(benchmarkRoot);
		Path storeDirectory = Files.createTempDirectory(benchmarkRoot, name + "-");
		try (EstimatorPropertyScope ignored = EstimatorPropertyScope.open(precision)) {
			LmdbStoreConfig config = ConfigUtil.createConfig();
			long checksum;
			LmdbStore store = new LmdbStore(storeDirectory.toFile(), config);
			SailRepository repository = new SailRepository(store);
			try {
				if (mode == LoadMode.BULK_REBUILD) {
					BenchmarkJoinEstimatorSupport.prepareEstimatorForBulkLoad(repository, store);
				} else {
					repository.init();
				}
				loadThemes(repository, themes);
				if (mode == LoadMode.BULK_REBUILD) {
					BenchmarkJoinEstimatorSupport.persistEstimatorAfterBulkLoad(repository, store);
				} else {
					BenchmarkJoinEstimatorSupport.persistStoreStatistics(store);
				}
				checksum = exerciseEstimator(repository, store, themes);
			} finally {
				repository.shutDown();
			}
			checksum += reopenAndExerciseEstimator(storeDirectory, config, themes);
			return checksum;
		} finally {
			FileUtils.deleteDirectory(storeDirectory.toFile());
		}
	}

	private long reopenAndExerciseEstimator(Path storeDirectory, LmdbStoreConfig config, List<Theme> themes)
			throws Exception {
		LmdbStore store = new LmdbStore(storeDirectory.toFile(), config);
		SailRepository repository = new SailRepository(store);
		try {
			repository.init();
			return exerciseEstimator(repository, store, themes);
		} finally {
			repository.shutDown();
		}
	}

	private static void loadThemes(SailRepository repository, List<Theme> themes) {
		for (Theme theme : themes) {
			try (var connection = repository.getConnection()) {
				connection.begin(IsolationLevels.READ_COMMITTED);
				try {
					ThemeDataSetGenerator.generate(theme, new RDFInserter(connection));
					connection.commit();
				} catch (RuntimeException | Error e) {
					connection.rollback();
					throw e;
				}
			}
		}
	}

	private static long exerciseEstimator(SailRepository repository, LmdbStore store, List<Theme> themes)
			throws Exception {
		SketchBasedJoinEstimator estimator = BenchmarkJoinEstimatorSupport.resolveEstimator(store);
		BenchmarkJoinEstimatorSupport.persistStoreStatistics(store);
		long checksum = probeEstimator(estimator, themes);
		BenchmarkJoinEstimatorSupport.releaseEstimatorMemory(store);
		checksum += probeEstimator(estimator, themes);
		checksum += executeSanityQuery(repository, themes);
		return checksum;
	}

	private static long probeEstimator(SketchBasedJoinEstimator estimator, List<Theme> themes) {
		String rdfType = RDF.TYPE.stringValue();
		String copy = LIBRARY + "Copy";
		String locatedAt = LIBRARY + "locatedAt";
		String branchZero = LIBRARY + "branch/0";
		String condition = MEDICAL + "Condition";
		String code = MEDICAL + "code";
		long checksum = Math.round(estimator.cardinalitySingle(Component.P, rdfType));
		if (themes.contains(Theme.LIBRARY)) {
			checksum += Math.round(estimator.cardinalityPair(Pair.PO, rdfType, copy));
			checksum += Math.round(estimator.estimateCount(Component.S, null, rdfType, copy, null));
			checksum += Math.round(estimator.estimate(Component.O, null, rdfType, copy, null)
					.join(Component.S, null, locatedAt, branchZero, null)
					.estimate());
		}
		if (themes.contains(Theme.MEDICAL_RECORDS)) {
			checksum += Math.round(estimator.cardinalityPair(Pair.PO, rdfType, condition));
			checksum += Math.round(estimator.estimate(Component.S, null, rdfType, condition, null)
					.join(Component.S, null, code, null, null)
					.estimate());
		}
		return checksum;
	}

	private static long executeSanityQuery(SailRepository repository, List<Theme> themes) {
		Theme theme = themes.contains(Theme.MEDICAL_RECORDS) ? Theme.MEDICAL_RECORDS : themes.get(0);
		int queryIndex = 0;
		String query = ThemeQueryCatalog.queryFor(theme, queryIndex);
		long expected = ThemeQueryCatalog.expectedCountFor(theme, queryIndex);
		try (var connection = repository.getConnection()) {
			TupleQuery tupleQuery = connection.prepareTupleQuery(query);
			try (TupleQueryResult result = tupleQuery.evaluate()) {
				long count = result.stream().count();
				if (count != expected) {
					throw new IllegalStateException("Unexpected count for " + theme + " q" + queryIndex
							+ ": expected " + expected + " but got " + count);
				}
				return count;
			}
		}
	}

	private List<Theme> selectedThemes() {
		if (themeSet == null || themeSet.isBlank() || "ALL".equalsIgnoreCase(themeSet.trim())) {
			return Arrays.asList(Theme.values());
		}
		List<Theme> themes = new ArrayList<>();
		for (String name : themeSet.split(",")) {
			String trimmed = name.trim();
			if (!trimmed.isEmpty()) {
				themes.add(Theme.valueOf(trimmed));
			}
		}
		if (themes.isEmpty()) {
			throw new IllegalArgumentException("No theme datasets selected by themeSet=" + themeSet);
		}
		return themes;
	}

	private enum LoadMode {
		INCREMENTAL,
		BULK_REBUILD
	}

	private record EstimatorPrecision(int bucketCount, int sketchNominalEntries) {
	}

	private static final class EstimatorPropertyScope implements AutoCloseable {
		private final Map<String, String> previousValues;

		private EstimatorPropertyScope(Map<String, String> previousValues) {
			this.previousValues = previousValues;
		}

		private static EstimatorPropertyScope open(EstimatorPrecision precision) {
			Map<String, String> properties = new LinkedHashMap<>();
			properties.put("nominalEntries", Integer.toString(precision.bucketCount()));
			properties.put("sketchK", Integer.toString(precision.sketchNominalEntries()));
			properties.put("residentSketchMemoryTargetPercent", "0.05");
			properties.put("residentSketchMemoryCeilingPercent", "0.08");
			properties.put("memoryMonitorIntervalMillis", "50");
			properties.put("memoryPressureUnloadBatchSize", "32");

			Map<String, String> previousValues = new LinkedHashMap<>();
			for (Map.Entry<String, String> entry : properties.entrySet()) {
				String propertyName = ESTIMATOR_PROPERTY_PREFIX + entry.getKey();
				previousValues.put(propertyName, System.getProperty(propertyName));
				System.setProperty(propertyName, entry.getValue());
			}
			return new EstimatorPropertyScope(previousValues);
		}

		@Override
		public void close() {
			for (Map.Entry<String, String> entry : previousValues.entrySet()) {
				if (entry.getValue() == null) {
					System.clearProperty(entry.getKey());
				} else {
					System.setProperty(entry.getKey(), entry.getValue());
				}
			}
		}
	}
}
